unsafe fn allocate_NONUPD(mut cap: *mut Capability, mut n_words: i32) -> StgPtr {
    return allocate(
        cap,
        ({
            let mut _a = (size_of::<StgHeader>() as u64)
                .wrapping_add(size_of::<W_>() as u64)
                .wrapping_sub(1 as u64)
                .wrapping_div(size_of::<W_>() as u64)
                .wrapping_add(1 as u64);

            let mut _b = n_words as u64;

            if _a <= _b { _b as u64 } else { _a as u64 }
        }) as W_,
    );
}

unsafe fn is_ret_bco_frame(frame_head: StgPtr) -> i32 {
    return (frame_head as W_ == &raw const stg_ret_t_info as W_
        || frame_head as W_ == &raw const stg_ret_v_info as W_
        || frame_head as W_ == &raw const stg_ret_p_info as W_
        || frame_head as W_ == &raw const stg_ret_n_info as W_
        || frame_head as W_ == &raw const stg_ret_f_info as W_
        || frame_head as W_ == &raw const stg_ret_d_info as W_
        || frame_head as W_ == &raw const stg_ret_l_info as W_) as i32;
}

pub(crate) static mut rts_stop_on_exception: i32 = 0;

pub(crate) static mut rts_stop_next_breakpoint: i32 = 0;

pub(crate) unsafe fn rts_enableStopNextBreakpointAll() {
    rts_stop_next_breakpoint = 1;
}

pub(crate) unsafe fn rts_disableStopNextBreakpointAll() {
    rts_stop_next_breakpoint = 0;
}

pub(crate) unsafe fn rts_enableStopNextBreakpoint(mut tso: *mut StgTSO) {
    (*tso).flags |= TSO_STOP_NEXT_BREAKPOINT as StgWord32;
}

pub(crate) unsafe fn rts_disableStopNextBreakpoint(mut tso: *mut StgTSO) {
    (*tso).flags &= !TSO_STOP_NEXT_BREAKPOINT as StgWord32;
}

pub(crate) unsafe fn rts_enableStopAfterReturn(mut tso: *mut StgTSO) {
    (*tso).flags |= TSO_STOP_AFTER_RETURN as StgWord32;
}

pub(crate) unsafe fn rts_disableStopAfterReturn(mut tso: *mut StgTSO) {
    (*tso).flags &= !TSO_STOP_AFTER_RETURN as StgWord32;
}

