unsafe fn newEmptyPAP(
    mut cap: *mut Capability,
    mut tagged_obj: *mut StgClosure,
    mut arity: u32,
) -> *mut StgClosure {
    let mut pap = allocate(
        cap,
        (size_of::<StgPAP>() as usize)
            .wrapping_add(size_of::<W_>() as usize)
            .wrapping_sub(1 as usize)
            .wrapping_div(size_of::<W_>() as usize) as W_,
    ) as *mut StgPAP;

    let ref mut fresh133 = (*(pap as *mut StgClosure)).header.prof.ccs;
    *fresh133 = (*cap).r.rCCCS as *mut CostCentreStack;

    if doingLDVProfiling() {
        if doingLDVProfiling() {
            (*(pap as *mut StgClosure)).header.prof.hp.ldvw =
                (era as StgWord) << LDV_SHIFT | LDV_STATE_CREATE as StgWord;
        }
    } else if doingRetainerProfiling() {
        (*(pap as *mut StgClosure)).header.prof.hp.trav = 0;
    } else if doingErasProfiling() {
        (*(pap as *mut StgClosure)).header.prof.hp.era = user_era;
    }

    (&raw mut (*pap).header.info).store(&raw const stg_PAP_info, Ordering::Relaxed);
    (*pap).arity = arity as StgHalfWord;
    (*pap).n_args = 0;
    (*pap).fun = tagged_obj;

    return pap as *mut StgClosure;
}

unsafe fn copyPAP(mut cap: *mut Capability, mut oldpap: *mut StgPAP) -> *mut StgClosure {
    let mut size: u32 = PAP_sizeW((*oldpap).n_args as u32) as u32;
    let mut pap = allocate(cap, size as W_) as *mut StgPAP;
    enterFunCCS(&raw mut (*cap).r, (*oldpap).header.prof.ccs);
    (*pap).arity = (*oldpap).arity;
    (*pap).n_args = (*oldpap).n_args;
    (*pap).fun = (*oldpap).fun;

    let mut i: u32 = 0;
    i = 0;

    while i < (*pap).n_args {
        let ref mut fresh134 =
            *(&raw mut (*pap).payload as *mut *mut StgClosure).offset(i as isize);
        *fresh134 = *(&raw mut (*oldpap).payload as *mut *mut StgClosure).offset(i as isize);
        i = i.wrapping_add(1);
    }

    let ref mut fresh135 = (*(pap as *mut StgClosure)).header.prof.ccs;
    *fresh135 = (*cap).r.rCCCS as *mut CostCentreStack;

    if doingLDVProfiling() {
        if doingLDVProfiling() {
            (*(pap as *mut StgClosure)).header.prof.hp.ldvw =
                (era as StgWord) << LDV_SHIFT | LDV_STATE_CREATE as StgWord;
        }
    } else if doingRetainerProfiling() {
        (*(pap as *mut StgClosure)).header.prof.hp.trav = 0;
    } else if doingErasProfiling() {
        (*(pap as *mut StgClosure)).header.prof.hp.era = user_era;
    }

    (&raw mut (*pap).header.info).store(&raw const stg_PAP_info, Ordering::Relaxed);

    return pap as *mut StgClosure;
}

unsafe fn slow_spw(
    mut Sp: *mut c_void,
    mut cur_stack: *mut StgStack,
    mut offset_words: StgWord,
) -> *mut c_void {
    if (((Sp as *mut StgWord8)
        .offset((offset_words as ptrdiff_t * size_of::<W_>() as ptrdiff_t) as isize)
        as *mut c_void as *mut StgWord)
        < (&raw mut (*cur_stack).stack as *mut StgWord)
            .offset((*cur_stack).stack_size as isize)
            .offset(
                -((size_of::<StgUnderflowFrame>() as usize)
                    .wrapping_add(size_of::<W_>() as usize)
                    .wrapping_sub(1 as usize)
                    .wrapping_div(size_of::<W_>() as usize) as isize),
            )) as i32 as i64
        != 0
    {
        return (Sp as *mut StgWord8)
            .offset((offset_words as ptrdiff_t * size_of::<W_>() as ptrdiff_t) as isize)
            as *mut c_void;
    } else {
        let mut stackWords: StgWord = 0;
        let mut frame = null_mut::<StgUnderflowFrame>();
        let mut new_stack = null_mut::<StgStack>();
        frame = (&raw mut (*cur_stack).stack as *mut StgWord)
            .offset((*cur_stack).stack_size as isize)
            .offset(
                -((size_of::<StgUnderflowFrame>() as usize)
                    .wrapping_add(size_of::<W_>() as usize)
                    .wrapping_sub(1 as usize)
                    .wrapping_div(size_of::<W_>() as usize) as isize),
            ) as *mut StgUnderflowFrame;

        if (*frame).info == &raw const stg_stack_underflow_frame_d_info
            || (*frame).info == &raw const stg_stack_underflow_frame_v16_info
            || (*frame).info == &raw const stg_stack_underflow_frame_v32_info
            || (*frame).info == &raw const stg_stack_underflow_frame_v64_info
        {
            new_stack = (*frame).next_chunk as *mut StgStack;
            stackWords = (frame as *mut StgWord).offset_from(Sp as *mut StgWord) as i64 as StgWord;

            if (offset_words > stackWords) as i32 as i64 != 0 {
            } else {
                _assertFail(c"rts/Interpreter.c".as_ptr(), 557);
            }

            return slow_spw(
                (*new_stack).sp as *mut c_void,
                new_stack,
                offset_words.wrapping_sub(stackWords),
            );
        } else {
            return (Sp as *mut StgWord8)
                .offset((offset_words as ptrdiff_t * size_of::<W_>() as ptrdiff_t) as isize)
                as *mut c_void;
        }
    };
}

unsafe fn tagConstr(mut con: *mut StgClosure) -> *mut StgClosure {
    return TAG_CLOSURE(
        ({
            let mut _a = (1 << 3) - 1;
            let mut _b = (1 as StgHalfWord).wrapping_add(GET_TAG(con)) as i32;

            if _a <= _b { _a as i32 } else { _b as i32 }
        }) as StgWord,
        con,
    );
}

